import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://open.larksuite.com/document/home/introduction-to-scope-and-authorization/access-credentials";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Lark Open Platform API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:lark",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const larkFirewall = {",
    '  name: "lark",',
    '  description: "Lark Open Platform API",',
    "  placeholders: {",
    `    LARK_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://open.larksuite.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.LARK_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://open.feishu.cn",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.LARK_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Lark firewall config...");
  const ts = generateTypeScript();
  writeOutput("lark", ts, import.meta.dirname);
}
